type Output = {
    images: string[];
    subject_texts: string[];
    imgs_duration: number[];
    error?: string;
};

async function main({ params }: Args): Promise<Output> {
    try {
        // 收集所有非空图片
        const all_imgs = [
            params.imgs_1,
            params.imgs_2,
            params.imgs_3,
            params.imgs_4,
            params.imgs_5,
            params.imgs_6,
            params.imgs_7,
            params.imgs_8,
            params.imgs_9,
            params.imgs_10
        ].filter(img => img && img.trim() !== "");

        const subject_texts = ['了不起的盖茨比', '挪威的森林', '海底两万里', '月亮与六便士', '小王子', '百年孤独', '平凡的世界', '边城', '活着', '朝花夕拾'];

        // 每张图片的帧数配置
        const imgs_frame = [5, 3, 4, 4, 4, 7, 5, 9, 7, 9];

        // 30fps，每帧1/30秒 = 1000000/30微秒 = 33333.333微秒，取整为33333
        const microseconds_per_frame = Math.round(1000000 / 30);

        // 根据实际图片数量调整帧数配置
        const actual_frames = imgs_frame.slice(0, all_imgs.length);

        // 计算每张图片的时长
        const imgs_duration = actual_frames.map(frame => frame * microseconds_per_frame);

        const ret = {
            images: all_imgs,
            subject_texts,
            imgs_duration
        };

        return ret;
    } catch (error) {
        // 异常处理
        return {
            images: [],
            subject_texts: [],
            imgs_duration: [],
            error: error.message || "处理过程中发生未知错误"
        };
    }
}

