async function main({ params }: Args): Promise<Output> {
    try {
        // 输入参数校验
        if (!params.kc_wenan_all_timeline || !Array.isArray(params.kc_wenan_all_timeline) || params.kc_wenan_all_timeline.length === 0) {
            throw new Error("时间轴配置不能为空");
        }

        if (!params.kc_img) {
            throw new Error("主图片不能为空");
        }

        // 获取开场时间范围
        const { start: kc_start, end: kc_end } = params.kc_wenan_all_timeline[0];

        // 计算开场时间轴的时长
        const kc_duration = kc_end - kc_start;

        // 生成新的 subject_timelines
        const subject_timelines = params.subject_timeline.map(timeline => ({
            start: timeline.start + kc_duration,
            end: timeline.end + kc_duration
        }));

        const ret = {
            kc_imgs: [params.kc_img],
            kc_texts: [params.kc_wenan],
            curr_subject_text: [params.subject],
            ft_audio_links: [params.ft_audio],
            ft_audio_timelines: [{ start: kc_end, end: kc_end + 2000000 }],
            kc_renwu_img: [params.kc_renwu_img],
            bgmusic: [params.bg_music],
            accountname: [params.account_name],
            subject_timelines
        };

        return ret;
    } catch (error) {
        // 异常处理
        return {
            kc_imgs: [],
            kc_texts: [],
            curr_subject_text: [],
            ft_audio_links: [],
            ft_audio_timelines: [],
