// 匀速慢速单向，位置为画布归一化坐标，已按缩放留安全边(|x|<=scale-1)
async function main({ params }: Args): Promise<Output> {
    function ensureList(v) {
        if (typeof v === 'string') { try { v = JSON.parse(v); } catch (e) { v = []; } }
        return Array.isArray(v) ? v : [];
    }
    const motionCycle = [
        {ss:1.45,sx:0.0,sy:0.0,es:1.78,ex:0.0,ey:-0.06},
        {ss:1.5,sx:0.06,sy:0.0,es:1.8,ex:-0.04,ey:0.0},
        {ss:1.62,sx:0.0,sy:0.02,es:1.68,ex:0.0,ey:-0.02},
        {ss:1.42,sx:0.0,sy:0.05,es:1.82,ex:0.0,ey:-0.05},
        {ss:1.72,sx:-0.3,sy:0.0,es:1.72,ex:0.3,ey:0.04},
        {ss:1.5,sx:-0.05,sy:0.0,es:1.76,ex:0.05,ey:0.0},
        {ss:1.66,sx:0.02,sy:0.0,es:1.6,ex:-0.02,ey:0.0},
        {ss:1.46,sx:0.0,sy:-0.04,es:1.8,ex:0.0,ey:0.05},
        {ss:1.88,sx:0.0,sy:0.0,es:1.52,ex:0.0,ey:0.0},
        {ss:1.5,sx:0.04,sy:0.04,es:1.78,ex:-0.04,ey:-0.04},
        {ss:1.7,sx:0.28,sy:-0.04,es:1.7,ex:-0.28,ey:0.0},
        {ss:1.6,sx:0.0,sy:0.0,es:1.66,ex:0.0,ey:0.03}
    ];
    const firstMotion = {ss:1.42,sx:0.0,sy:0.0,es:1.75,ex:0.0,ey:-0.05};
    const calmMotion  = {ss:1.64,sx:0.0,sy:0.0,es:1.58,ex:0.0,ey:0.0};
    const finalMotion = {ss:1.5,sx:0.0,sy:0.1,es:1.8,ex:0.0,ey:-0.12};

    const segs = ensureList(params.image_segment_infos);
    const valid = [];
    for (const seg of segs) {
        if (!seg || typeof seg !== 'object') continue;
        const id = String(seg.id || '').trim();
        const start = parseInt(seg.start || 0, 10) || 0;
        const end = parseInt(seg.end || start, 10) || start;
        if (!id || end <= start) continue;
        valid.push([id, start, end]);
    }
    const total = valid.length;
    const keyframes = [];
    for (let idx = 0; idx < total; idx++) {
        const id = valid[idx][0], start = valid[idx][1], end = valid[idx][2];
        let motion;
        if (idx === 0) motion = firstMotion;
        else if (total >= 4 && idx === total - 1) motion = finalMotion;
        else if (total >= 6 && idx === total - 2) motion = calmMotion;
        else motion = motionCycle[idx % motionCycle.length];
        const dur = end - start;
        keyframes.push({offset:0,  property:'KFTypePositionX', segment_id:id, value:motion.sx});
        keyframes.push({offset:dur,property:'KFTypePositionX', segment_id:id, value:motion.ex});
        keyframes.push({offset:0,  property:'KFTypePositionY', segment_id:id, value:motion.sy});
        keyframes.push({offset:dur,property:'KFTypePositionY', segment_id:id, value:motion.ey});
        keyframes.push({offset:0,  property:'UNIFORM_SCALE',   segment_id:id, value:motion.ss});
        keyframes.push({offset:dur,property:'UNIFORM_SCALE',   segment_id:id, value:motion.es});
    }
    return { keyframes: JSON.stringify(keyframes) };
}
